use std::collections::HashMap;

struct GameCommandProcessor {
    actions: HashMap<String, String>,
}

impl GameCommandProcessor {
    fn new() -> Self {
        let mut actions = HashMap::new();
        actions.insert("walk".to_string(), "Move character forward".to_string());
        actions.insert("jump".to_string(), "Apply vertical force".to_string());
        actions.insert("emote".to_string(), "Trigger animation cycle".to_string());
        GameCommandProcessor { actions }
    }

    fn process_sequence(&self, sequence: &str) -> Vec<String> {
        let mut detected_commands = Vec::new();
        let words = sequence.split("_");
        for word in words {
            let trimmed_word = word.trim();
            if !trimmed_word.is_empty() && self.actions.contains_key(trimmed_word) {
                detected_commands.push(format!("{}", trimmed_word));
            }
        }
        detected_commands
    }
}

fn main() {
    let processor = GameCommandProcessor::new();
    let command_string = "walk_jump_emote_walk";
    let commands = processor.process_sequence(command_string);

    println!("Original sequence: {}", command_string);
    println!("Detected actions: {:?}", commands);
}

use std::collections::HashMap;

struct Record {
    id: u32,
    data: String,
}

fn process_names(names: Vec<String>) -> HashMap<u32, String> {
    let mut index = HashMap::new();
    for (i, name) in names.into_iter().enumerate() {
        let record = Record { id: i as u32, data: name };
        index.insert(record.id, record.data);
    }
    index
}

fn main() {
    let initial_names = vec![
        String::from("Résumé"),
        String::from("Straße"),
        String::from("你好")
    ];

    let processed_index = process_names(initial_names);

    println!("Successfully indexed records:");
    for (id, data) in processed_index {
        println!("ID {}: {}", id, data);
    }
}

use std::collections::VecDeque;

struct DataParser {
    buffer: VecDeque<u8>,
}

impl DataParser {
    fn new() -> Self {
        DataParser { buffer: VecDeque::new() }
    }

    fn ingest_bytes(&mut self, data: &[u8]) {
        for &byte in data { 
            self.buffer.push_back(byte);
        }
    }

    fn extract_chars(&mut self) -> String {
        let mut result = String::new();
        while let Some(first_byte) = self.buffer.pop_front() {
            match char::from_u32(u32::from_be_bytes([first_byte, 0, 0, 0])) {
                Some(c) => {
                    result.push(c);
                }
                None => {
                    self.buffer.push_back(first_byte);
                    break;
                }
            }
        }
        result
    }
}

fn main() {
    let mut parser = DataParser::new();
    let raw_data: Vec<u8> = vec![0x48, 0x65, 0x6C, 0x6C, 0x6F, 0xC3, 0xA9, 0xFF]; 
    parser.ingest_bytes(&raw_data);

    let extracted = parser.extract_chars();
    println!("Successfully parsed data: {}", extracted);
}

use std::io::{self, Write};
use unicode_segmentation;

fn main() -> io::Result<()> {
    let user_ids = vec![
        "user123",
        "id-456",
        "über-test",
        "validID",
        "résumé789",
    ];

    for id in user_ids {
        let mut problematic_char: Option<char> = None;
        for c in id.chars() {
            if !c.is_ascii_alphanumeric() && !c.is_ascii_punctuation() {
                problematic_char = Some(c);
                break;
            }
        }

        match problematic_char {
            Some(c) => write!(io::stdout(), "ID: {}", id),
            None => write!(io::stdout(), "ID: {}", id),
        };

        if let Some(c) = problematic_char {
            println!(" -> Found unusual character: '{}'", c);
        } else {
            println!(" -> All characters seem fine.");
        }
    }
    Ok(())
}

use std::fs;
use std::io::{self, BufRead};
use std::collections::HashSet;

fn main() -> io::Result<()> {
    let file_paths = vec!["log1.txt", "log2.txt"];
    let mut unique_ips: HashSet<String> = HashSet::new();

    for path in file_paths {
        println!("Processing {}", path);
        let file = fs::File::open(path)?;
        let reader = io::BufReader::new(file);
        for line in reader.lines() {
            let line = line?;
            if line.contains("192.168.") {
                if let Some(start) = line.find(":") {
                    let ip_segment = &line[..start];
                    unique_ips.insert(ip_segment.to_string());
                }
            }
        }
    }

    println!("n--- Unique IPs Found -----n");
    for ip in unique_ips {
        println!("{}", ip);
    }
    Ok(())
}
